//! Behavioral + parity tests for the ES module (`es.zig`): numpy-reference
//! goldens (generated by tools/gen_es_goldens.py — regenerate there, paste
//! here), noise-scheme semantics, restore modes, replica materialization,
//! chunk-parallel determinism, the step/evaluateMembers drivers, registry
//! integration, tripwires, and end-to-end convergence on a sphere objective.
//!
//! Golden tolerances: es.zig draws noise through `rng.gaussianFillAtFast`
//! (f32 polynomial transcendentals) while the numpy generator uses f64 libm
//! — same uniforms, values a few f32 ulps apart — so numpy goldens compare
//! with per-dtype tolerances instead of bitwise (same policy as the torch
//! optimizer goldens; sigma scaling shrinks the noise deltas well below
//! every tolerance). Bitwise guarantees are covered separately by the
//! test-local serial reference (same kernel at runtime) and the
//! twin-trainer tests.

const std = @import("std");
const ag = @import("ag.zig");
const dtype_mod = @import("dtype.zig");
const es = @import("es.zig");
const exec_mod = @import("exec.zig");
const param_registry_mod = @import("param_registry.zig");
const rng = @import("rng.zig");

const ExecContext = exec_mod.ExecContext;
const ParamRegistry = param_registry_mod.ParamRegistry;
const Tensor = ag.Tensor;

const F16Tensor = Tensor(.{ .dtype = .f16, .tags = .{.n} });
const Bf16Tensor = Tensor(.{ .dtype = .bf16, .tags = .{.n} });

fn expectCloseSlices(expected: []const f32, actual: []const f32, tolerance: f32) !void {
    try std.testing.expectEqual(expected.len, actual.len);
    for (expected, actual) |e, a| {
        try std.testing.expectApproxEqAbs(e, a, tolerance);
    }
}

fn widenF16(dst: []f32, src: []const f16) void {
    for (dst, src) |*d, s| d.* = @floatCast(s);
}

fn widenBf16(dst: []f32, src: []const u16) void {
    for (dst, src) |*d, s| d.* = dtype_mod.bf16ToF32(s);
}

// The golden scenario's parameters (tools/gen_es_goldens.py).
const theta_a = [_]f32{ 0.8, -1.25, 0.5, 2.0, -0.125, 1.5, -0.75 };
const theta_b = [_]f16{ 0.5, -0.25, 1.0, -1.5, 2.0, 0.125, -0.875, 0.0625 };
const theta_c_f32 = [_]f32{ 1.0, -2.0, 0.5, -0.25, 3.0 };
const theta_d = [_]f32{ -0.5, 0.75, -1.0, 0.25, 1.125, -2.5, 0.375 };

/// The four golden slots as facade tensors (a/d f32, b f16, c bf16 — a and d
/// share a length so the correlated scheme is observable). `b` is a VARIABLE
/// to cover the autograd-facade registration path; ES treats it identically.
const GoldenParams = struct {
    a: Tensor(.{.n}),
    b: F16Tensor,
    c: Bf16Tensor,
    d: Tensor(.{.n}),

    fn init(ctx: *ExecContext) !GoldenParams {
        var theta_c_bits: [theta_c_f32.len]u16 = undefined;
        for (&theta_c_bits, theta_c_f32) |*bits, v| bits.* = dtype_mod.f32ToBf16(v);

        var a = try Tensor(.{.n}).fromSlice(ctx, .{theta_a.len}, &theta_a);
        errdefer a.deinit();
        var b = try F16Tensor.fromSlice(ctx, .{theta_b.len}, &theta_b);
        errdefer b.deinit();
        var c = try Bf16Tensor.fromSlice(ctx, .{theta_c_f32.len}, &theta_c_bits);
        errdefer c.deinit();
        const d = try Tensor(.{.n}).variableFromSlice(ctx, .{theta_d.len}, &theta_d);
        return .{ .a = a, .b = b, .c = c, .d = d };
    }

    fn deinit(self: *GoldenParams) void {
        self.d.deinit();
        self.c.deinit();
        self.b.deinit();
        self.a.deinit();
        self.* = undefined;
    }

    fn register(self: *GoldenParams, trainer: *es.Trainer) !void {
        try trainer.addParamNamed(&self.a, "a");
        try trainer.addParamNamed(&self.b, "b");
        try trainer.addParamNamed(&self.c, "c");
        try trainer.addParamNamed(&self.d, "d");
    }

    /// Widened views of the four slots for tolerance comparison.
    fn expectClose(self: *const GoldenParams, ea: []const f32, eb: []const f32, ec: []const f32, ed: []const f32) !void {
        var wide_b: [theta_b.len]f32 = undefined;
        widenF16(&wide_b, try self.b.dataConst());
        var wide_c: [theta_c_f32.len]f32 = undefined;
        widenBf16(&wide_c, try self.c.dataConst());
        // f32 slots: tight (libm ulp headroom only). f16/bf16: half an ulp at
        // the slot's magnitude — a flipped rounding from a 1-ulp noise
        // difference stays within, a missing/misplaced update does not.
        try expectCloseSlices(ea, try self.a.dataConst(), 1e-6);
        try expectCloseSlices(eb, &wide_b, 1e-3);
        try expectCloseSlices(ec, &wide_c, 1.6e-2);
        try expectCloseSlices(ed, try self.d.dataConst(), 1e-6);
    }
};

