test "es config validation" {
    const allocator = std.testing.allocator;
    try std.testing.expectError(es.EsError.InvalidConfig, es.Trainer.init(allocator, .{ .sigma = 0 }));
    try std.testing.expectError(es.EsError.InvalidConfig, es.Trainer.init(allocator, .{ .sigma = -0.1 }));
    try std.testing.expectError(es.EsError.InvalidConfig, es.Trainer.init(allocator, .{ .alpha = 0 }));
    try std.testing.expectError(es.EsError.InvalidConfig, es.Trainer.init(allocator, .{ .population = 1 }));
    var trainer = try es.Trainer.init(allocator, .{});
    defer trainer.deinit();
    try std.testing.expectEqual(@as(f32, 0.0005), trainer.alphaValue()); // sigma/2 default
}

test "es golden: perturb matches the numpy reference, restore bounds the drift" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    var params = try GoldenParams.init(&ctx);
    defer params.deinit();
    var trainer = try es.Trainer.init(allocator, config_a);
    defer trainer.deinit();
    try params.register(&trainer);
    try std.testing.expectEqual(@as(usize, 4), trainer.paramCount());
    try std.testing.expectEqual(theta_a.len + theta_b.len + theta_c_f32.len + theta_d.len, trainer.elementCount());

    try trainer.perturb(&ctx, 2);
    try params.expectClose(&golden_perturbed_m2_a, &golden_perturbed_m2_b, &golden_perturbed_m2_c, &golden_perturbed_m2_d);

    // Regenerate-restore drift: bounded by one rounding of the perturbed
    // value per element ((x + t) - t), i.e. ~an ulp at the slot's magnitude.
    try trainer.restore(&ctx, 2);
    var wide_b: [theta_b.len]f32 = undefined;
    widenF16(&wide_b, try params.b.dataConst());
    var wide_c: [theta_c_f32.len]f32 = undefined;
    widenBf16(&wide_c, try params.c.dataConst());
    var theta_b_f32: [theta_b.len]f32 = undefined;
    widenF16(&theta_b_f32, &theta_b);
    try expectCloseSlices(&theta_a, try params.a.dataConst(), 1e-6);
    try expectCloseSlices(&theta_b_f32, &wide_b, 2e-3);
    try expectCloseSlices(&theta_c_f32, &wide_c, 3.2e-2);
    try expectCloseSlices(&theta_d, try params.d.dataConst(), 1e-6);
}

test "es golden: two z-score updates match the numpy reference (scenario A)" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    var params = try GoldenParams.init(&ctx);
    defer params.deinit();
    var trainer = try es.Trainer.init(allocator, config_a);
    defer trainer.deinit();
    try params.register(&trainer);

    const stats0 = try trainer.update(&ctx, &rewards_iter0);
    // f32 reward literals are inexact, so the f64 mean is only ~1e-8 close.
    try std.testing.expectApproxEqAbs(@as(f64, 0.2375), stats0.mean_reward, 1e-7);
    try std.testing.expectEqual(@as(f32, -0.4), stats0.min_reward);
    try std.testing.expectEqual(@as(f32, 0.9), stats0.max_reward);
    try std.testing.expectEqual(@as(u64, 1), trainer.iteration);
    _ = try trainer.update(&ctx, &rewards_iter1);
    try std.testing.expectEqual(@as(u64, 2), trainer.iteration);

    try params.expectClose(&golden_a_after2_a, &golden_a_after2_b, &golden_a_after2_c, &golden_a_after2_d);
}

