test "es centered ranks: outlier clamped, ties pinned by member index, all-equal steps anyway" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    // Zero parameters expose the applied coefficients directly:
    // theta' = scale * sum_n C_n * eps_n with theta = 0 and one member's
    // noise recovered via materializeMember... simpler: verify through the
    // update's EFFECT — an outlier reward must not dominate. Two trainers,
    // same seed: one gets a catastrophic outlier reward, one a mild one; the
    // rank-shaped updates must be IDENTICAL (ranks see only the ordering).
    inline for (0..2) |variant| {
        const zeros = [_]f32{0} ** 64;
        var w = try Tensor(.{.n}).fromSlice(&ctx, .{zeros.len}, &zeros);
        defer w.deinit();
        var trainer = try es.Trainer.init(allocator, .{
            .sigma = 0.1,
            .alpha = 0.05,
            .population = 4,
            .reward_norm = .centered_ranks,
            .seed = 77,
        });
        defer trainer.deinit();
        try trainer.addParam(&w);
        // Same ordering, wildly different magnitudes (variant 1 has the
        // CE-14-style catastrophic member).
        const rewards: [4]f32 = if (variant == 0) .{ -4.0, -4.5, -3.9, -5.0 } else .{ -4.0, -4.5, -3.9, -1.0e6 };
        _ = try trainer.update(&ctx, &rewards);
        if (variant == 0) {
            // Stash the reference update for the comparison below.
            @memcpy(rank_update_scratch[0..zeros.len], try w.dataConst());
        } else {
            try std.testing.expectEqualSlices(f32, rank_update_scratch[0..zeros.len], try w.dataConst());
        }
    }

    // All-equal rewards: unlike z_score's exact zero update, ranks still
    // spread members over [-0.5, 0.5] (tie order = member index) and take a
    // mean-zero phantom step — documented behavior, pinned here.
    {
        const zeros = [_]f32{0} ** 8;
        var w = try Tensor(.{.n}).fromSlice(&ctx, .{zeros.len}, &zeros);
        defer w.deinit();
        var trainer = try es.Trainer.init(allocator, .{
            .sigma = 0.1,
            .alpha = 0.05,
            .population = 3,
            .reward_norm = .centered_ranks,
            .seed = 78,
        });
        defer trainer.deinit();
        try trainer.addParam(&w);
        _ = try trainer.update(&ctx, &.{ 0.7, 0.7, 0.7 });
        var moved = false;
        for (try w.dataConst()) |x| moved = moved or (x != 0);
        try std.testing.expect(moved);
    }
}

var rank_update_scratch: [64]f32 = undefined;

test "es antithetic: mirrored pairs, folded update matches a signed serial reference" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    // Mirror structure: on zero parameters (fl(0 + t) = t exactly) member
    // 2k+1's perturbation is the exact negation of member 2k's.
    {
        const zeros = [_]f32{0} ** 32;
        var w = try Tensor(.{.n}).fromSlice(&ctx, .{zeros.len}, &zeros);
        defer w.deinit();
        var trainer = try es.Trainer.init(allocator, .{ .sigma = 0.1, .population = 4, .antithetic = true, .seed = 31 });
        defer trainer.deinit();
        try trainer.addParam(&w);

        var plus: [zeros.len]f32 = undefined;
        try trainer.perturb(&ctx, 0);
        @memcpy(&plus, try w.dataConst());
        try trainer.restore(&ctx, 0);
        try trainer.perturb(&ctx, 1);
        for (plus, try w.dataConst()) |p, m| try std.testing.expectEqual(-p, m);
        try trainer.restore(&ctx, 1);

        // materializeMember carries the same signs.
        const replica = try allocator.alloc(f32, zeros.len);
        defer allocator.free(replica);
        try trainer.materializeMember(1, &.{std.mem.sliceAsBytes(replica)});
        for (plus, replica) |p, m| try std.testing.expectEqual(-p, m);
    }

    // Folded update == signed straight-line serial reference (bitwise):
    // per pair k the contribution is (C_2k - C_2k+1) * eps_k, division by
    // the FULL population.
    {
        const n = 10_000;
        const population = 6;
        const theta0 = try allocator.alloc(f32, n);
        defer allocator.free(theta0);
        rng.uniformFill(3, theta0, -1.0, 1.0);
        var w = try Tensor(.{.n}).fromSlice(&ctx, .{n}, theta0);
        defer w.deinit();
        var trainer = try es.Trainer.init(allocator, .{
            .sigma = 0.05,
            .alpha = 0.02,
            .population = population,
            .antithetic = true,
            .noise = .correlated, // public memberSeed = the stream seed
            .reward_norm = .z_score,
            .seed = 13,
        });
        defer trainer.deinit();
        try trainer.addParam(&w);

        const rewards = [_]f32{ 0.5, -0.25, 1.5, 1.0, -2.0, 0.0 };
        var mean: f64 = 0;
        for (rewards) |r| mean += r;
        mean /= rewards.len;
        var variance: f64 = 0;
        for (rewards) |r| variance += (r - mean) * (r - mean);
        variance /= rewards.len;
        const std_reward = @sqrt(variance);
        var coeffs: [population]f32 = undefined;
        for (&coeffs, rewards) |*c, r| c.* = @floatCast((r - mean) / (std_reward + 1e-8));

        const expected = try allocator.dupe(f32, theta0);
        defer allocator.free(expected);
        const noise = try allocator.alloc(f32, n);
        defer allocator.free(noise);
        const acc = try allocator.alloc(f32, n);
        defer allocator.free(acc);
        @memset(acc, 0);
        for (0..population / 2) |pair| {
            rng.gaussianFillAtFast(trainer.memberSeed(2 * pair), 0, noise, 1.0);
            const folded = coeffs[2 * pair] - coeffs[2 * pair + 1];
            for (acc, noise) |*a, eps| a.* += folded * eps;
        }
        const scale = trainer.alphaValue() / @as(f32, population);
        for (expected, acc) |*p, a| p.* += scale * a;

        _ = try trainer.update(&ctx, &rewards);
        try std.testing.expectEqualSlices(f32, expected, try w.dataConst());
    }

    // Odd population + antithetic is a config error.
    try std.testing.expectError(es.EsError.InvalidConfig, es.Trainer.init(allocator, .{ .population = 3, .antithetic = true }));
}

test "es antithetic converges on the sphere objective" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    const n = 16;
    var w = try Tensor(.{.n}).fromSlice(&ctx, .{n}, &([_]f32{1.0} ** n));
    defer w.deinit();
    var trainer = try es.Trainer.init(allocator, .{ .sigma = 0.1, .alpha = 0.05, .population = 16, .antithetic = true, .seed = 1234 });
    defer trainer.deinit();
    try trainer.addParam(&w);

    const Evaluator = struct {
        w: *const Tensor(.{.n}),

        fn sqNorm(self: *const @This()) !f64 {
            var total: f64 = 0;
            for (try self.w.dataConst()) |x| total += @as(f64, x) * @as(f64, x);
            return total;
        }

        pub fn eval(self: *const @This(), member: usize) !f32 {
            _ = member;
            return @floatCast(-(try self.sqNorm()));
        }
    };
    const evaluator = Evaluator{ .w = &w };
    const initial = 16.0;
    for (0..150) |_| _ = try trainer.step(&ctx, &evaluator);
    var final: f64 = 0;
    for (try w.dataConst()) |x| final += @as(f64, x) * @as(f64, x);
    try std.testing.expect(final < initial * 0.25);
}

test "es stream cache: cached and uncached runs are bitwise identical" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    inline for (.{ false, true }) |antithetic| {
        const configs = [2]es.Config{
            .{ .sigma = 0.05, .population = 4, .antithetic = antithetic, .restore_mode = .snapshot, .seed = 55 },
            .{ .sigma = 0.05, .population = 4, .antithetic = antithetic, .restore_mode = .snapshot, .seed = 55, .cache_streams = true },
        };
        var thetas: [2][2][]f32 = undefined; // [trainer][slot]
        inline for (0..2) |which| {
            var a = try Tensor(.{.n}).fromSlice(&ctx, .{theta_a.len}, &theta_a);
            defer a.deinit();
            var d = try Tensor(.{.n}).fromSlice(&ctx, .{theta_d.len}, &theta_d);
            defer d.deinit();
            var trainer = try es.Trainer.init(allocator, configs[which]);
            defer trainer.deinit();
            try trainer.addParam(&a);
            try trainer.addParam(&d);

            // Two full iterations: perturb/eval/restore every member (the
            // eval fills the cache), then update; second iteration reuses
            // the machinery post-invalidation.
            inline for (.{ [_]f32{ 0.1, 0.9, -0.4, 0.35 }, [_]f32{ 1.0, -1.0, 0.25, 0.5 } }) |rewards| {
                for (0..4) |member| {
                    try trainer.perturb(&ctx, member);
                    try trainer.restore(&ctx, member);
                }
                _ = try trainer.update(&ctx, &rewards);
            }
            thetas[which][0] = try allocator.dupe(f32, try a.dataConst());
            thetas[which][1] = try allocator.dupe(f32, try d.dataConst());
        }
        defer for (thetas) |pair| for (pair) |t| allocator.free(t);
        try std.testing.expectEqualSlices(f32, thetas[0][0], thetas[1][0]);
        try std.testing.expectEqualSlices(f32, thetas[0][1], thetas[1][1]);
    }
}

test "es anchored weight decay: l2 proximal pull matches the formula bitwise, l1 thresholds to the anchor" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    const theta0 = [_]f32{ 0.8, -1.25, 0.5, 2.0, -0.125, 1.5, -0.75, 0.0625 };
    const rewards = [_]f32{ 0.1, 0.9, -0.4, 0.35 };

    // Plain ES twin: theta_es after one update, no decay.
    var w_es = try Tensor(.{.n}).fromSlice(&ctx, .{theta0.len}, &theta0);
    defer w_es.deinit();
    var plain = try es.Trainer.init(allocator, .{ .sigma = 0.05, .alpha = 0.02, .population = 4, .seed = 42 });
    defer plain.deinit();
    try plain.addParam(&w_es);
    _ = try plain.update(&ctx, &rewards);

    // AWD twin: identical config + l2 anchor decay from theta0.
    var w_awd = try Tensor(.{.n}).fromSlice(&ctx, .{theta0.len}, &theta0);
    defer w_awd.deinit();
    var anchored = try es.Trainer.init(allocator, .{
        .sigma = 0.05,
        .alpha = 0.02,
        .population = 4,
        .seed = 42,
        .anchor_decay = .l2,
        .anchor_lambda = 10,
    });
    defer anchored.deinit();
    try anchored.addParam(&w_awd);
    try anchored.captureAnchor();
    _ = try anchored.update(&ctx, &rewards);

    // theta_awd == theta_0 + (1 - alpha*lambda) * (theta_es - theta_0),
    // replicated with the kernel's exact f32 op order (single narrowing).
    const keep: f32 = 1 - 0.02 * 10.0;
    for (try w_es.dataConst(), try w_awd.dataConst(), theta0) |es_v, awd_v, a| {
        const expected = a + (es_v - a) * keep;
        try std.testing.expectEqual(expected, awd_v);
    }

    // l1 with a huge threshold collapses the whole update: theta returns to
    // the anchor bitwise (softshrink zeroes every |d| < alpha*lambda).
    var w_l1 = try Tensor(.{.n}).fromSlice(&ctx, .{theta0.len}, &theta0);
    defer w_l1.deinit();
    var strong = try es.Trainer.init(allocator, .{
        .sigma = 0.05,
        .alpha = 0.02,
        .population = 4,
        .seed = 42,
        .anchor_decay = .l1,
        .anchor_lambda = 1e6,
    });
    defer strong.deinit();
    try strong.addParam(&w_l1);
    try strong.captureAnchor();
    _ = try strong.update(&ctx, &rewards);
    try std.testing.expectEqualSlices(f32, &theta0, try w_l1.dataConst());

    // Validation and the missing-anchor tripwire.
    try std.testing.expectError(es.EsError.InvalidConfig, es.Trainer.init(allocator, .{ .anchor_decay = .l2 })); // lambda 0
    try std.testing.expectError(es.EsError.InvalidConfig, es.Trainer.init(allocator, .{
        .alpha = 0.5,
        .anchor_decay = .l2,
        .anchor_lambda = 2, // alpha*lambda = 1: the l2 shrink degenerates
    }));
    var w_missing = try Tensor(.{.n}).fromSlice(&ctx, .{4}, &.{ 1, 2, 3, 4 });
    defer w_missing.deinit();
    var no_anchor = try es.Trainer.init(allocator, .{ .population = 4, .anchor_decay = .l2, .anchor_lambda = 1 });
    defer no_anchor.deinit();
    try no_anchor.addParam(&w_missing);
    try std.testing.expectError(es.EsError.AnchorMissing, no_anchor.update(&ctx, &.{ 0.0, 1.0, 2.0, 3.0 }));
}

