test "es update matches a straight-line serial reference bitwise (chunk-parallel path)" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    // Large enough to fan out over the worker team (update_min_len = 2^11).
    const n = 40_000;
    const population = 5;
    const theta0 = try allocator.alloc(f32, n);
    defer allocator.free(theta0);
    rng.uniformFill(7, theta0, -2.0, 2.0);

    var w = try Tensor(.{.n}).fromSlice(&ctx, .{n}, theta0);
    defer w.deinit();
    // .correlated so the noise stream seed is the PUBLIC memberSeed (the
    // reference below needs it without touching module internals).
    var trainer = try es.Trainer.init(allocator, .{ .sigma = 0.01, .alpha = 0.004, .population = population, .noise = .correlated, .reward_norm = .z_score, .seed = 99 });
    defer trainer.deinit();
    try trainer.addParam(&w);

    // Independent serial reference: z-score coefficients (f64 stats, ddof=0,
    // +1e-8 on the std), fp32 mul-then-add accumulation in member order,
    // one final alpha/population scaling, plain f32 add.
    const rewards = [_]f32{ 0.3, -1.2, 0.75, 0.0, 2.5 };
    var mean: f64 = 0;
    for (rewards) |r| mean += r;
    mean /= rewards.len;
    var variance: f64 = 0;
    for (rewards) |r| variance += (r - mean) * (r - mean);
    variance /= rewards.len;
    const std_reward = @sqrt(variance);
    var coeffs: [population]f32 = undefined;
    for (&coeffs, rewards) |*c, r| c.* = @floatCast((r - mean) / (std_reward + 1e-8));

    const expected = try allocator.alloc(f32, n);
    defer allocator.free(expected);
    @memcpy(expected, theta0);
    const noise = try allocator.alloc(f32, n);
    defer allocator.free(noise);
    const acc = try allocator.alloc(f32, n);
    defer allocator.free(acc);
    @memset(acc, 0);
    for (0..population) |member| {
        rng.gaussianFillAtFast(trainer.memberSeed(member), 0, noise, 1.0);
        for (acc, noise) |*a, eps| a.* += coeffs[member] * eps;
    }
    const scale = trainer.alphaValue() / @as(f32, population);
    for (expected, acc) |*p, a| p.* += scale * a;

    _ = try trainer.update(&ctx, &rewards);
    try std.testing.expectEqualSlices(f32, expected, try w.dataConst());
}

test "es step equals manual update on a twin (snapshot restore), advances iteration" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    var config = config_a;
