    defer trainer.deinit();
    try params.register(&trainer);

    var twin_params = try GoldenParams.init(&ctx);
    defer twin_params.deinit();
    var twin = try es.Trainer.init(allocator, config);
    defer twin.deinit();
    try twin_params.register(&twin);

    // Deterministic per-member rewards; records the visit order.
    const Evaluator = struct {
        visited: std.ArrayList(usize) = .empty,
        allocator: std.mem.Allocator,

        pub fn eval(self: *@This(), member: usize) !f32 {
            try self.visited.append(self.allocator, member);
            return @as(f32, @floatFromInt(member)) * 0.5 - 0.3;
        }
    };
    var evaluator = Evaluator{ .allocator = allocator };
    defer evaluator.visited.deinit(allocator);

    _ = try trainer.step(&ctx, &evaluator);
    try std.testing.expectEqualSlices(usize, &.{ 0, 1, 2, 3 }, evaluator.visited.items);
    try std.testing.expectEqual(@as(u64, 1), trainer.iteration);

    var rewards: [4]f32 = undefined;
    for (&rewards, 0..) |*r, member| r.* = @as(f32, @floatFromInt(member)) * 0.5 - 0.3;
    _ = try twin.update(&ctx, &rewards);

    try std.testing.expectEqualSlices(f32, try twin_params.a.dataConst(), try params.a.dataConst());
    try std.testing.expectEqualSlices(f16, try twin_params.b.dataConst(), try params.b.dataConst());
    try std.testing.expectEqualSlices(u16, try twin_params.c.dataConst(), try params.c.dataConst());
    try std.testing.expectEqualSlices(f32, try twin_params.d.dataConst(), try params.d.dataConst());
}

test "es evaluateMembers: parallel replica evaluation equals sequential" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    const n = 512;
    const population = 12;
    const theta0 = try allocator.alloc(f32, n);
    defer allocator.free(theta0);
    rng.uniformFill(21, theta0, -1.0, 1.0);
    var w = try Tensor(.{.n}).fromSlice(&ctx, .{n}, theta0);
    defer w.deinit();

    var trainer = try es.Trainer.init(allocator, .{ .sigma = 0.1, .population = population, .seed = 5 });
    defer trainer.deinit();
    try trainer.addParam(&w);

    // One replica per worker; the reward is a deterministic function of the
    // materialized parameters, so parallel == sequential exactly.
    const workers = 4;
    const Evaluator = struct {
        trainer: *const es.Trainer,
        replicas: *[workers][]f32,

        pub fn evalMember(self: *const @This(), worker: usize, member: usize) !f32 {
            const replica = self.replicas[worker];
            try self.trainer.materializeMember(member, &.{std.mem.sliceAsBytes(replica)});
            var sum: f64 = 0;
            for (replica) |x| sum += x;
            return @floatCast(sum);
        }
    };
    var replicas: [workers][]f32 = undefined;
    var built: usize = 0;
    defer for (replicas[0..built]) |r| allocator.free(r);
    for (&replicas) |*r| {
        r.* = try allocator.alloc(f32, n);
        built += 1;
    }
    const evaluator = Evaluator{ .trainer = &trainer, .replicas = &replicas };

    var sequential: [population]f32 = undefined;
    try trainer.evaluateMembers(&evaluator, &sequential, 1);
    var parallel_rewards: [population]f32 = undefined;
    try trainer.evaluateMembers(&evaluator, &parallel_rewards, workers);
    try std.testing.expectEqualSlices(f32, &sequential, &parallel_rewards);

    // theta untouched by replica evaluation.
    try std.testing.expectEqualSlices(f32, theta0, try w.dataConst());
}

