test "es tripwires and misuse errors" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    var w = try Tensor(.{.n}).fromSlice(&ctx, .{4}, &.{ 1, 2, 3, 4 });
    defer w.deinit();
    var trainer = try es.Trainer.init(allocator, .{ .population = 2 });
    defer trainer.deinit();

    // No params yet.
    try std.testing.expectError(es.EsError.NoParams, trainer.perturb(&ctx, 0));
    try std.testing.expectError(es.EsError.NoParams, trainer.update(&ctx, &.{ 0.0, 1.0 }));

    try trainer.addParam(&w);
    try std.testing.expectError(es.EsError.DuplicateParam, trainer.addParam(&w));

    try std.testing.expectError(es.EsError.MemberNotActive, trainer.restore(&ctx, 0));
    try trainer.perturb(&ctx, 0);
    try std.testing.expectError(es.EsError.MemberActive, trainer.perturb(&ctx, 1));
    try std.testing.expectError(es.EsError.MemberActive, trainer.update(&ctx, &.{ 0.0, 1.0 }));
    try std.testing.expectError(es.EsError.MemberNotActive, trainer.restore(&ctx, 1)); // wrong member
    const dst = [_][]u8{&.{}};
    try std.testing.expectError(es.EsError.MemberActive, trainer.materializeMember(0, &dst));
    // Growing the parameter set mid-perturbation would desynchronize
    // restore (and invalidate a snapshot slab) — same tripwire.
    var w2 = try Tensor(.{.n}).fromSlice(&ctx, .{2}, &.{ 9, 9 });
    defer w2.deinit();
    try std.testing.expectError(es.EsError.MemberActive, trainer.addParam(&w2));
    try trainer.restore(&ctx, 0);
    try trainer.addParam(&w2); // fine once restored

    try std.testing.expectError(es.EsError.RewardCountMismatch, trainer.update(&ctx, &.{0.0}));
    try std.testing.expectError(es.EsError.ReplicaShapeMismatch, trainer.materializeMember(0, &dst));

    // evaluateMembers rejects workers == 0 (the `worker < workers` replica
    // bound would otherwise be violated by the implicit 0 -> 1 clamp).
    const NoopEval = struct {
        pub fn evalMember(_: *const @This(), _: usize, _: usize) !f32 {
            return 0;
        }
    };
    var zero_rewards: [2]f32 = undefined;
    try std.testing.expectError(es.EsError.InvalidConfig, trainer.evaluateMembers(&NoopEval{}, &zero_rewards, 0));
}

