// --- Ternary genome slots (BlockTQ2_0 crumbs, EGGROLL-style updates) ---

/// Test-local crumb accessors replicating the tq2_0 layout contract
/// (block e/256; r = e%256: group r/128, lane (r%128)/32, byte (r%128)%32).
fn ternaryCode(blocks: []const es.BlockTQ2_0, e: usize) u8 {
    const r = e % 256;
    const shift: u3 = @intCast(2 * ((r % 128) / 32));
    return (blocks[e / 256].qs[(r / 128) * 32 + (r % 128) % 32] >> shift) & 3;
}

fn ternarySetCode(blocks: []es.BlockTQ2_0, e: usize, code: u8) void {
    const r = e % 256;
    const shift: u3 = @intCast(2 * ((r % 128) / 32));
    const byte = &blocks[e / 256].qs[(r / 128) * 32 + (r % 128) % 32];
    byte.* = (byte.* & ~(@as(u8, 3) << shift)) | (code << shift);
}

/// Blocks with independent random crumbs in {0, 1, 2} and DISTINCT d bits
/// per block (ES must never touch d).
fn ternaryRandomBlocks(allocator: std.mem.Allocator, n_blocks: usize, seed: u64) ![]es.BlockTQ2_0 {
    const blocks = try allocator.alloc(es.BlockTQ2_0, n_blocks);
    for (blocks, 0..) |*block, b| {
        for (&block.qs, 0..) |*q, i| {
            var byte: u8 = 0;
            for (0..4) |lane| {
                const code: u8 = @intCast(rng.at(seed, @intCast((b * 64 + i) * 4 + lane)) % 3);
                byte |= code << @as(u3, @intCast(2 * lane));
            }
            q.* = byte;
        }
        block.d = @intCast(0x3C00 + b);
    }
    return blocks;
}

/// Blocks with every crumb equal to `code` (0/1/2 = w -1/0/+1).
fn ternaryConstBlocks(allocator: std.mem.Allocator, n_blocks: usize, code: u8) ![]es.BlockTQ2_0 {
    const blocks = try allocator.alloc(es.BlockTQ2_0, n_blocks);
    for (blocks) |*block| {
        @memset(&block.qs, code * 0b01010101);
        block.d = 0x3C00;
    }
    return blocks;
}

/// Replay one slot's flip stream in stream order (the perturb contract:
/// index = at(seed, 2i) % len, delta bit at(seed, 2i+1) & 1 -> +/-1, clamped
/// one-bin moves; colliding flips compose sequentially).
fn ternaryReplicaFlips(blocks: []es.BlockTQ2_0, len: usize, stream_seed: u64, flips: usize) void {
    for (0..flips) |i| {
        const index: usize = @intCast(rng.at(stream_seed, 2 * @as(u64, @intCast(i))) % @as(u64, len));
        const delta: i8 = if (rng.at(stream_seed, 2 * @as(u64, @intCast(i)) + 1) & 1 == 1) 1 else -1;
        const w = @as(i8, @intCast(ternaryCode(blocks, index))) - 1;
        ternarySetCode(blocks, index, @intCast(std.math.clamp(w + delta, -1, 1) + 1));
    }
}

const TernaryUpdateReplica = struct { expected: []es.BlockTQ2_0, touched: usize };

/// Single-voter replica of the vote-and-threshold update on one slot:
/// accumulate the votes of one coefficient-1.0 stream (the tests reward
/// member 0 with 1.0 and everyone else 0 under .none shaping, so only this
/// stream contributes nonzero votes), sort them by (|vote| desc, index asc),
/// and apply the top `cap` clamped one-bin moves to a copy of `before`.
/// Returns the copy plus the touched-nonzero count (the other binding term
/// of the applied-move budget). Caller frees `expected`.
fn ternaryReplicaUpdate(
    allocator: std.mem.Allocator,
    before: []const es.BlockTQ2_0,
    len: usize,
    stream_seed: u64,
    flips: usize,
    cap: usize,
) !TernaryUpdateReplica {
    const votes = try allocator.alloc(f32, len);
    defer allocator.free(votes);
    @memset(votes, 0);
    for (0..flips) |i| {
        const index: usize = @intCast(rng.at(stream_seed, 2 * @as(u64, @intCast(i))) % @as(u64, len));
        votes[index] += if (rng.at(stream_seed, 2 * @as(u64, @intCast(i)) + 1) & 1 == 1) 1.0 else -1.0;
    }
    const touched = try allocator.alloc(usize, len);
    defer allocator.free(touched);
    var n_touched: usize = 0;
    for (votes, 0..) |v, e| {
        if (v != 0) {
            touched[n_touched] = e;
            n_touched += 1;
        }
    }
    std.mem.sort(usize, touched[0..n_touched], @as([]const f32, votes), struct {
        fn lessThan(v: []const f32, a: usize, b: usize) bool {
            if (@abs(v[a]) != @abs(v[b])) return @abs(v[a]) > @abs(v[b]);
            return a < b;
        }
    }.lessThan);
    const expected = try allocator.dupe(es.BlockTQ2_0, before);
    for (touched[0..@min(n_touched, cap)]) |e| {
        const w = @as(i8, @intCast(ternaryCode(expected, e))) - 1;
        const sign: i8 = if (votes[e] > 0) 1 else -1;
        ternarySetCode(expected, e, @intCast(std.math.clamp(w + sign, -1, 1) + 1));
    }
    return .{ .expected = expected, .touched = n_touched };
}

test "es ternary config validation and registration errors" {
    const allocator = std.testing.allocator;
    try std.testing.expectError(es.EsError.InvalidConfig, es.Trainer.init(allocator, .{ .ternary_flip_rate = 0 }));
    try std.testing.expectError(es.EsError.InvalidConfig, es.Trainer.init(allocator, .{ .ternary_flip_rate = 1.5 }));
    try std.testing.expectError(es.EsError.InvalidConfig, es.Trainer.init(allocator, .{ .ternary_update_fraction = 0 }));
    try std.testing.expectError(es.EsError.InvalidConfig, es.Trainer.init(allocator, .{ .ternary_update_decay = -0.5 }));

    var trainer = try es.Trainer.init(allocator, .{ .population = 2 });
    defer trainer.deinit();
    const blocks = try ternaryConstBlocks(allocator, 2, 1);
    defer allocator.free(blocks);
    try std.testing.expectError(es.EsError.InvalidConfig, trainer.addTernaryParam(blocks, 0));
    try std.testing.expectError(es.EsError.InvalidConfig, trainer.addTernaryParam(blocks, 500)); // not a multiple of 256
    try std.testing.expectError(es.EsError.InvalidConfig, trainer.addTernaryParam(blocks, 256)); // blocks.len != len/256
    try trainer.addTernaryParam(blocks, 512);
    try std.testing.expectError(es.EsError.DuplicateParam, trainer.addTernaryParam(blocks, 512));
    try std.testing.expectEqual(@as(usize, 1), trainer.paramCount());
    try std.testing.expectEqual(@as(usize, 512), trainer.elementCount());
}

test "es ternary registration rejects crumb code 3, accepts the repaired genome" {
    const allocator = std.testing.allocator;
    var trainer = try es.Trainer.init(allocator, .{ .population = 2 });
    defer trainer.deinit();

    // Crumb code 3 never comes out of the encoders but can arrive in a
    // corrupt/untrusted GGUF; registration must reject it up front.
    // Registration pins len to whole blocks (len % 256 == 0), so every
    // stored crumb is logical — there is no partial-block tail to exempt.
    const blocks = try ternaryRandomBlocks(allocator, 2, 0xC0DE);
    defer allocator.free(blocks);
    ternarySetCode(blocks, 300, 3);
    try std.testing.expectError(es.EsError.InvalidConfig, trainer.addTernaryParam(blocks, 512));
    try std.testing.expectEqual(@as(usize, 0), trainer.paramCount());

    ternarySetCode(blocks, 300, 2); // repaired genome registers fine
    try trainer.addTernaryParam(blocks, 512);
    try std.testing.expectEqual(@as(usize, 1), trainer.paramCount());
}

test "es ternary perturb/restore round-trips bitwise (clamp-heavy included)" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    inline for (.{ false, true }) |clamp_heavy| {
        // Clamp-heavy: an all-(+1) genome saturates every +1 delta, so the
        // undo log must restore through no-op flips and rail collisions.
        const blocks = if (clamp_heavy)
            try ternaryConstBlocks(allocator, 3, 2)
        else
            try ternaryRandomBlocks(allocator, 3, 0xABCD);
        defer allocator.free(blocks);
        var trainer = try es.Trainer.init(allocator, .{
            .population = 4,
            .ternary_flip_rate = 0.05, // 38 flips over 768 elements: collisions occur
            .seed = 9,
        });
        defer trainer.deinit();
        try trainer.addTernaryParam(blocks, 768);
        const before = try allocator.dupe(es.BlockTQ2_0, blocks);
        defer allocator.free(before);
        for (0..4) |member| {
            try trainer.perturb(&ctx, member);
            try std.testing.expect(!std.mem.eql(u8, std.mem.sliceAsBytes(before), std.mem.sliceAsBytes(blocks)));
            try trainer.restore(&ctx, member);
            try std.testing.expectEqualSlices(u8, std.mem.sliceAsBytes(before), std.mem.sliceAsBytes(blocks));
        }
    }
}

