test "es ternary antithetic: odd member mirrors the even member's deltas" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    // Zero genome (every w = 0, code 1) exposes the raw deltas; the clamp
    // is odd-symmetric on [-1, +1], so colliding flips mirror too.
    const len = 512;
    const base = try ternaryConstBlocks(allocator, 2, 1);
    defer allocator.free(base);
    var trainer = try es.Trainer.init(allocator, .{
        .population = 4,
        .antithetic = true,
        .ternary_flip_rate = 16.0 / 512.0,
        .seed = 33,
    });
    defer trainer.deinit();
    try trainer.addTernaryParam(base, len);

    const even = try allocator.alloc(es.BlockTQ2_0, 2);
    defer allocator.free(even);
    const odd = try allocator.alloc(es.BlockTQ2_0, 2);
    defer allocator.free(odd);
    try trainer.materializeTernaryMember(2, &.{even});
    try trainer.materializeTernaryMember(3, &.{odd});

    var flipped: usize = 0;
    for (0..len) |e| {
        const w_even = @as(i8, @intCast(ternaryCode(even, e))) - 1;
        const w_odd = @as(i8, @intCast(ternaryCode(odd, e))) - 1;
        try std.testing.expectEqual(w_even, -w_odd);
        if (w_even != 0) flipped += 1;
        try std.testing.expectEqual(@as(u8, 1), ternaryCode(base, e)); // shared genome untouched
    }
    try std.testing.expect(flipped > 0);
}

test "es ternary update: top-K one-bin moves toward sign(vote), crumbs ternary, d untouched" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    const len = 512;
    const cap = 8; // round(len * ternary_update_fraction)
    const blocks = try ternaryRandomBlocks(allocator, len / 256, 0x7E57);
    defer allocator.free(blocks);
    const before = try allocator.dupe(es.BlockTQ2_0, blocks);
    defer allocator.free(before);

    var trainer = try es.Trainer.init(allocator, .{
        .population = 2,
        .reward_norm = .none, // coefficients == rewards: exact replication below
        .ternary_flip_rate = 32.0 / 512.0,
        .ternary_update_fraction = 8.0 / 512.0,
        .seed = 21,
    });
    defer trainer.deinit();
    try trainer.addTernaryParam(blocks, len);

    // Replicate the vote table from the PUBLIC seed derivations before the
    // update advances the iteration: member 0 votes with coefficient 1;
    // member 1's zero-coefficient flips add exact zeros (dropped by the
    // nonzero filter), so only member 0's stream matters.
    const stream_seed = es.Trainer.ternarySlotStreamSeed(trainer.ternaryMemberSeed(0), 0);
    const flips = trainer.ternaryFlipCount(len);
    try std.testing.expectEqual(@as(usize, 32), flips);
    var votes = [_]f32{0} ** len;
    for (0..flips) |i| {
        const index: usize = @intCast(rng.at(stream_seed, 2 * @as(u64, @intCast(i))) % @as(u64, len));
        const delta: f32 = if (rng.at(stream_seed, 2 * @as(u64, @intCast(i)) + 1) & 1 == 1) 1.0 else -1.0;
        votes[index] += delta;
    }

    _ = try trainer.update(&ctx, &.{ 1.0, 0.0 });

    // Expected genome: sort nonzero votes by (|vote| desc, index asc), move
    // the top `cap` one bin toward sign(vote) with ternary clamping.
    var touched: [len]usize = undefined;
    var n_touched: usize = 0;
    for (votes, 0..) |v, e| {
        if (v != 0) {
            touched[n_touched] = e;
            n_touched += 1;
        }
    }
    std.mem.sort(usize, touched[0..n_touched], @as([]const f32, &votes), struct {
        fn lessThan(v: []const f32, a: usize, b: usize) bool {
            if (@abs(v[a]) != @abs(v[b])) return @abs(v[a]) > @abs(v[b]);
            return a < b;
        }
    }.lessThan);
    const expected = try allocator.dupe(es.BlockTQ2_0, before);
    defer allocator.free(expected);
    for (touched[0..@min(n_touched, cap)]) |e| {
        const w = @as(i8, @intCast(ternaryCode(expected, e))) - 1;
        const sign: i8 = if (votes[e] > 0) 1 else -1;
        ternarySetCode(expected, e, @intCast(std.math.clamp(w + sign, -1, 1) + 1));
    }
    try std.testing.expectEqualSlices(u8, std.mem.sliceAsBytes(expected), std.mem.sliceAsBytes(blocks));

    // The named invariants, asserted directly as well.
    var changed: usize = 0;
    for (0..len) |e| {
        const now = ternaryCode(blocks, e);
        try std.testing.expect(now <= 2);
        const was = ternaryCode(before, e);
        if (now != was) {
            changed += 1;
            const diff = @as(i8, @intCast(now)) - @as(i8, @intCast(was));
            try std.testing.expect(diff == 1 or diff == -1); // exactly one bin
            try std.testing.expectEqual(votes[e] > 0, diff == 1); // toward sign(vote)
        }
    }
    try std.testing.expect(changed > 0);
    try std.testing.expect(changed <= cap);
    for (before, blocks) |b, a| try std.testing.expectEqual(b.d, a.d);
}

test "es ternary update decay shrinks the top-K budget at iteration 1" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    const len = 512;
    // fraction 16/512 -> undecayed cap 16; decay 1 at iteration 1 halves it
    // to round(16 / (1 + 1*1)) = 8. A broken schedule fails the exact count
    // below: no decay applies 16 moves, an off-by-one iteration rounds
    // 16/3 to 5.
    const cap_iter1 = 8;
    // All-zero genome: no move can clamp into a no-op, so the changed-crumb
    // count equals the applied-move count.
    const blocks = try ternaryConstBlocks(allocator, len / 256, 1);
    defer allocator.free(blocks);

    var trainer = try es.Trainer.init(allocator, .{
        .population = 2,
        .reward_norm = .none, // coefficients == rewards: exact replication below
        .ternary_flip_rate = 32.0 / 512.0,
        .ternary_update_fraction = 16.0 / 512.0,
        .ternary_update_decay = 1.0,
        .seed = 63,
    });
    defer trainer.deinit();
    try trainer.addTernaryParam(blocks, len);

    // First update: zero coefficients vote nothing, so the genome stays
    // all-zero while the iteration (the decay schedule input) advances.
    _ = try trainer.update(&ctx, &.{ 0.0, 0.0 });
    try std.testing.expectEqual(@as(u64, 1), trainer.iteration);
    for (0..len) |e| try std.testing.expectEqual(@as(u8, 1), ternaryCode(blocks, e));

    // Replicate member 0's iteration-1 vote table from the public seed API
    // (member 1's coefficient is 0: exact-zero votes are dropped).
    const stream_seed = es.Trainer.ternarySlotStreamSeed(trainer.ternaryMemberSeed(0), 0);
    const replica = try ternaryReplicaUpdate(allocator, blocks, len, stream_seed, trainer.ternaryFlipCount(len), cap_iter1);
    defer allocator.free(replica.expected);
    try std.testing.expect(replica.touched > cap_iter1); // the budget, not the vote count, binds

    _ = try trainer.update(&ctx, &.{ 1.0, 0.0 });
    try std.testing.expectEqualSlices(u8, std.mem.sliceAsBytes(replica.expected), std.mem.sliceAsBytes(blocks));
    var changed: usize = 0;
    for (0..len) |e| changed += @intFromBool(ternaryCode(blocks, e) != 1);
    try std.testing.expectEqual(@min(replica.touched, cap_iter1), changed);
}

test "es ternary multi-slot: flip streams, perturbations, and votes stay per-slot" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    const len_a = 256;
    const len_b = 512;
    const blocks_a = try ternaryRandomBlocks(allocator, len_a / 256, 0xA5A5);
    defer allocator.free(blocks_a);
    const blocks_b = try ternaryRandomBlocks(allocator, len_b / 256, 0x5A5A);
    defer allocator.free(blocks_b);

    var trainer = try es.Trainer.init(allocator, .{
        .population = 2,
        .reward_norm = .none, // coefficients == rewards: exact replication below
        .ternary_flip_rate = 16.0 / 512.0, // 8 flips on slot 0, 16 on slot 1
        .ternary_update_fraction = 8.0 / 512.0, // top-K caps 4 and 8
        .seed = 47,
    });
    defer trainer.deinit();
    try trainer.addTernaryParamNamed(blocks_a, len_a, "a");
    try trainer.addTernaryParamNamed(blocks_b, len_b, "b");
    try std.testing.expectEqual(@as(usize, 2), trainer.paramCount());
    try std.testing.expectEqual(@as(usize, len_a + len_b), trainer.elementCount());

    // The two slots draw DISTINCT flip streams for the same member; compare
    // the raw draws under a common modulus so the length difference cannot
    // mask identical streams.
    const member_seed = trainer.ternaryMemberSeed(0);
    const seed_a = es.Trainer.ternarySlotStreamSeed(member_seed, 0);
    const seed_b = es.Trainer.ternarySlotStreamSeed(member_seed, 1);
    var streams_differ = false;
    for (0..2 * trainer.ternaryFlipCount(len_a)) |j| {
        if (rng.at(seed_a, @intCast(j)) % len_a != rng.at(seed_b, @intCast(j)) % len_a) streams_differ = true;
    }
    try std.testing.expect(streams_differ);

    // In-place perturb applies each slot's OWN stream (replicated bitwise
    // from the public seed API); restore unwinds both undo logs.
    const before_a = try allocator.dupe(es.BlockTQ2_0, blocks_a);
    defer allocator.free(before_a);
    const before_b = try allocator.dupe(es.BlockTQ2_0, blocks_b);
    defer allocator.free(before_b);
    const perturbed_a = try allocator.dupe(es.BlockTQ2_0, blocks_a);
    defer allocator.free(perturbed_a);
    ternaryReplicaFlips(perturbed_a, len_a, seed_a, trainer.ternaryFlipCount(len_a));
    const perturbed_b = try allocator.dupe(es.BlockTQ2_0, blocks_b);
    defer allocator.free(perturbed_b);
    ternaryReplicaFlips(perturbed_b, len_b, seed_b, trainer.ternaryFlipCount(len_b));
    try trainer.perturb(&ctx, 0);
    try std.testing.expectEqualSlices(u8, std.mem.sliceAsBytes(perturbed_a), std.mem.sliceAsBytes(blocks_a));
    try std.testing.expectEqualSlices(u8, std.mem.sliceAsBytes(perturbed_b), std.mem.sliceAsBytes(blocks_b));
    try trainer.restore(&ctx, 0);
    try std.testing.expectEqualSlices(u8, std.mem.sliceAsBytes(before_a), std.mem.sliceAsBytes(blocks_a));
    try std.testing.expectEqualSlices(u8, std.mem.sliceAsBytes(before_b), std.mem.sliceAsBytes(blocks_b));

    // The update votes per slot: each genome must land exactly on its OWN
    // replicated top-K table (cross-slot vote leakage — e.g. a missing
    // per-slot vote reset — would push slot 0's indices into slot 1's cap).
    const replica_a = try ternaryReplicaUpdate(allocator, before_a, len_a, seed_a, trainer.ternaryFlipCount(len_a), 4);
    defer allocator.free(replica_a.expected);
    const replica_b = try ternaryReplicaUpdate(allocator, before_b, len_b, seed_b, trainer.ternaryFlipCount(len_b), 8);
    defer allocator.free(replica_b.expected);
    try std.testing.expect(replica_a.touched > 0);
    try std.testing.expect(replica_b.touched > 0);
    _ = try trainer.update(&ctx, &.{ 1.0, 0.0 });
    try std.testing.expectEqualSlices(u8, std.mem.sliceAsBytes(replica_a.expected), std.mem.sliceAsBytes(blocks_a));
    try std.testing.expectEqualSlices(u8, std.mem.sliceAsBytes(replica_b.expected), std.mem.sliceAsBytes(blocks_b));
}

test "es ternary: mixed float+ternary trainer leaves float slots bitwise unchanged" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    const n = 512;
    const theta0 = try allocator.alloc(f32, n);
    defer allocator.free(theta0);
    rng.uniformFill(17, theta0, -1.0, 1.0);
    const config = es.Config{ .sigma = 0.05, .alpha = 0.02, .population = 4, .seed = 42 };
    const rewards = [_]f32{ 0.3, -1.2, 0.75, 0.0 };

    // Float-only twin.
    var w_float = try Tensor(.{.n}).fromSlice(&ctx, .{n}, theta0);
    defer w_float.deinit();
    var float_only = try es.Trainer.init(allocator, config);
    defer float_only.deinit();
    try float_only.addParam(&w_float);

    // Mixed twin: the ternary slot registers FIRST — float noise streams
    // key on the float slot index, so they must not shift.
    const blocks = try ternaryRandomBlocks(allocator, 2, 0xB17);
    defer allocator.free(blocks);
    var w_mixed = try Tensor(.{.n}).fromSlice(&ctx, .{n}, theta0);
    defer w_mixed.deinit();
    var mixed = try es.Trainer.init(allocator, config);
    defer mixed.deinit();
    try mixed.addTernaryParamNamed(blocks, 512, "genome");
    try mixed.addParam(&w_mixed);
    try std.testing.expectEqual(@as(usize, 2), mixed.paramCount());
    try std.testing.expectEqual(@as(usize, n + 512), mixed.elementCount());

    // Perturbation of the float slot is bitwise identical...
    try float_only.perturb(&ctx, 1);
    try mixed.perturb(&ctx, 1);
    try std.testing.expectEqualSlices(f32, try w_float.dataConst(), try w_mixed.dataConst());
    try float_only.restore(&ctx, 1);
    try mixed.restore(&ctx, 1);

    // ...and so is the update on the same rewards.
    _ = try float_only.update(&ctx, &rewards);
    _ = try mixed.update(&ctx, &rewards);
    try std.testing.expectEqualSlices(f32, try w_float.dataConst(), try w_mixed.dataConst());
}

test "es ternary converges toward a target genome (hamming reward)" {
    var gpa = std.heap.DebugAllocator(.{}){};
    defer std.testing.expect(gpa.deinit() == .ok) catch @panic("leak");
    const allocator = gpa.allocator();
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    const len = 512;
    const blocks = try ternaryConstBlocks(allocator, 2, 1); // start at all-zero weights
    defer allocator.free(blocks);
    var target: [len]u8 = undefined;
    for (&target, 0..) |*t, e| t.* = @intCast(rng.at(99, @intCast(e)) % 3);

    var trainer = try es.Trainer.init(allocator, .{
        .population = 32,
        .antithetic = true,
        .ternary_flip_rate = 4.0 / 512.0,
        .ternary_update_fraction = 8.0 / 512.0,
        .seed = 7,
    });
    defer trainer.deinit();
    try trainer.addTernaryParam(blocks, len);

    const Evaluator = struct {
        blocks: []const es.BlockTQ2_0,
        target: []const u8,

        fn distance(self: *const @This()) usize {
            var dist: usize = 0;
            for (self.target, 0..) |t, e| {
                if (ternaryCode(self.blocks, e) != t) dist += 1;
            }
            return dist;
        }

        pub fn eval(self: *const @This(), member: usize) !f32 {
            _ = member; // the flips are already applied in place
            return -@as(f32, @floatFromInt(self.distance())) / @as(f32, @floatFromInt(self.target.len));
        }
    };
    const evaluator = Evaluator{ .blocks = blocks, .target = &target };

    const initial = evaluator.distance();
    for (0..300) |_| _ = try trainer.step(&ctx, &evaluator);
    const final = evaluator.distance();
    try std.testing.expect(final * 5 <= initial * 2); // >= 60% closer
}

test "es ternary-only trainer: captureAnchor succeeds, anchored decay is a float no-op" {
    const allocator = std.testing.allocator;
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    // Both slot kinds empty still rejects captureAnchor.
    var empty = try es.Trainer.init(allocator, .{ .population = 2, .anchor_decay = .l2, .anchor_lambda = 10 });
    defer empty.deinit();
    try std.testing.expectError(es.EsError.NoParams, empty.captureAnchor());

    // Ternary-only trainer: AWD is a float-slot regularizer, so the anchor
    // is an empty slab and update must not fail AnchorMissing.
    const len = 512;
    const blocks = try ternaryRandomBlocks(allocator, len / 256, 0xA7C4);
    defer allocator.free(blocks);
    var trainer = try es.Trainer.init(allocator, .{
        .population = 2,
        .anchor_decay = .l2,
        .anchor_lambda = 10, // alpha*lambda = 0.005 < 1
        .ternary_flip_rate = 8.0 / 512.0,
        .ternary_update_fraction = 8.0 / 512.0,
        .seed = 11,
    });
    defer trainer.deinit();
    try trainer.addTernaryParam(blocks, len);
    try trainer.captureAnchor();

    // A full perturb/evaluate/restore/update cycle completes (this errored
    // AnchorMissing forever before captureAnchor accepted ternary-only)...
    const Evaluator = struct {
        pub fn eval(_: *const @This(), member: usize) !f32 {
            return @floatFromInt(member % 2);
        }
    };
    _ = try trainer.step(&ctx, &Evaluator{});
    try std.testing.expectEqual(@as(u64, 1), trainer.iteration);
    // ...and the genome stays a valid ternary model.
    for (0..len) |e| try std.testing.expect(ternaryCode(blocks, e) <= 2);
}

test "es update: allocation failure leaves theta, genome, and iteration untouched" {
    const allocator = std.testing.allocator;
    var ctx: ExecContext = undefined;
    ctx.init(allocator);
    defer ctx.deinit();

    const n = 32;
    const len = 256;
    var theta0: [n]f32 = undefined;
    rng.uniformFill(3, &theta0, -1.0, 1.0);
    const config = es.Config{ .population = 2, .reward_norm = .none, .seed = 5 };
    const rewards = [_]f32{ 1.0, 0.0 };
    const blocks0 = try ternaryRandomBlocks(allocator, len / 256, 0xFA11);
    defer allocator.free(blocks0);

    // Reference outcome from an unconstrained twin.
    var expected_theta: [n]f32 = undefined;
    const expected_blocks = try allocator.dupe(es.BlockTQ2_0, blocks0);
    defer allocator.free(expected_blocks);
    {
        var w = try Tensor(.{.n}).fromSlice(&ctx, .{n}, &theta0);
        defer w.deinit();
        var twin = try es.Trainer.init(allocator, config);
        defer twin.deinit();
        try twin.addParam(&w);
        try twin.addTernaryParam(expected_blocks, len);
        _ = try twin.update(&ctx, &rewards);
        @memcpy(&expected_theta, try w.dataConst());
    }

    // Sweep the failure point across every trainer-side allocation: a
    // failed update must be a no-op on theta, the genome, and `iteration`
    // (the mutate-last contract — the ternary vote scratch in particular
    // must allocate BEFORE the float slots change); past the last
    // allocation the update must succeed with the reference outcome.
    var failed_once = false;
    var fail_index: usize = 0;
    while (fail_index < 1000) : (fail_index += 1) {
        var failing = std.testing.FailingAllocator.init(allocator, .{ .fail_index = fail_index });
        var w = try Tensor(.{.n}).fromSlice(&ctx, .{n}, &theta0);
        defer w.deinit();
        const blocks = try allocator.dupe(es.BlockTQ2_0, blocks0);
        defer allocator.free(blocks);
        var trainer = try es.Trainer.init(failing.allocator(), config);
        defer trainer.deinit();
        // Registration allocates too; a failure there just advances the sweep.
        trainer.addParam(&w) catch |err| switch (err) {
            error.OutOfMemory => continue,
            else => return err,
        };
        trainer.addTernaryParam(blocks, len) catch |err| switch (err) {
            error.OutOfMemory => continue,
            else => return err,
        };
        if (trainer.update(&ctx, &rewards)) |_| {
            try std.testing.expectEqualSlices(f32, &expected_theta, try w.dataConst());
            try std.testing.expectEqualSlices(u8, std.mem.sliceAsBytes(expected_blocks), std.mem.sliceAsBytes(blocks));
            try std.testing.expectEqual(@as(u64, 1), trainer.iteration);
            try std.testing.expect(failed_once); // the sweep saw real OOM failures first
            return;
        } else |err| {
            if (err != error.OutOfMemory) return err;
            failed_once = true;
            try std.testing.expectEqualSlices(f32, &theta0, try w.dataConst());
            try std.testing.expectEqualSlices(u8, std.mem.sliceAsBytes(blocks0), std.mem.sliceAsBytes(blocks));
            try std.testing.expectEqual(@as(u64, 0), trainer.iteration);
        }
    }
    return error.TestUnexpectedResult; // the sweep never reached a successful update
}
